import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import { LayoutDashboard, Users, Calendar, Activity, LogOut, Heart, Shield } from 'lucide-react';

export default function AdminDashboard() {
  const { logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('overview');
  const [bookings, setBookings] = useState([]);
  const [caregivers, setCaregivers] = useState([]);

  useEffect(() => {
    const token = localStorage.getItem("token");

    axios.get('http://localhost:5000/api/bookings', {
      headers: { Authorization: `Bearer ${token}` }
    }).then(r => setBookings(r.data));

    axios.get('http://localhost:5000/api/caregivers', {
      headers: { Authorization: `Bearer ${token}` }
    }).then(r => setCaregivers(r.data));

  }, []);

  const updateStatus = async (id, newStatus) => {
    const token = localStorage.getItem("token");

    try {
      await axios.patch(
        `http://localhost:5000/api/bookings/${id}/status`,
        { status: newStatus },
        {
          headers: { Authorization: `Bearer ${token}` }
        }
      );

      setBookings(prev =>
        prev.map(b =>
          b._id === id ? { ...b, status: newStatus } : b
        )
      );

    } catch (err) {
      console.log(err);
      alert("Failed to update status");
    }
  };

  const stats = [
    { label: 'Total Bookings', value: bookings.length, icon: Calendar },
    { label: 'Caregivers', value: caregivers.length, icon: Users },
    { label: 'Active', value: bookings.filter(b => b.status === 'active').length, icon: Activity },
    { label: 'Pending', value: bookings.filter(b => b.status === 'pending').length, icon: Shield },
  ];

  return (
    <div className="dashboard-layout">

      {/* SIDEBAR */}
      <aside className="sidebar">
        <div className="sidebar-logo">
          <Heart size={18} /> Admin Panel
        </div>

        <nav className="sidebar-nav">
          <div className={`sidebar-item ${activeTab === 'overview' ? 'active' : ''}`} onClick={() => setActiveTab('overview')}>
            <LayoutDashboard size={18} /> Overview
          </div>
          <div className={`sidebar-item ${activeTab === 'bookings' ? 'active' : ''}`} onClick={() => setActiveTab('bookings')}>
            <Calendar size={18} /> Bookings
          </div>
          <div className={`sidebar-item ${activeTab === 'caregivers' ? 'active' : ''}`} onClick={() => setActiveTab('caregivers')}>
            <Users size={18} /> Caregivers
          </div>
        </nav>

        <div style={{ marginTop: 'auto' }}>
          <div className="sidebar-item" onClick={() => { logout(); navigate('/'); }}>
            <LogOut size={18} /> Logout
          </div>
        </div>
      </aside>

      {/* MAIN */}
      <main className="main-content">

        {/* OVERVIEW */}
        {activeTab === 'overview' && (
          <>
            <div className="page-header">
              <h1 className="page-title">Admin Dashboard</h1>
            </div>

            <div className="stats-grid">
              {stats.map((s, i) => (
                <div key={i} className="card stat-card">
                  <div className="stat-value">{s.value}</div>
                  <div className="stat-label">{s.label}</div>
                </div>
              ))}
            </div>
          </>
        )}

        {/* BOOKINGS */}
        {activeTab === 'bookings' && (
          <>
            <h2 className="section-title">All Bookings</h2>

            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Patient</th>
                    <th>Care Type</th>
                    <th>Caregiver</th>
                    <th>Status</th>
                  </tr>
                </thead>

                <tbody>
                  {bookings.map(b => (
                    <tr key={b._id}>
                      <td>{b.patient?.name}</td>

                      <td>
                        <span className="badge badge-teal">{b.careType}</span>
                      </td>

                      <td>
                        {b.caregiverId?.user?.name || "Not Selected"}
                      </td>

                      <td>
                        <div className="flex gap-2 items-center">

                          <span className={`badge status-${b.status}`}>
                            {b.status}
                          </span>

                          {/* 🔥 STATUS UPDATE */}
                          <select
                            className="form-select"
                            style={{ padding: '4px 8px', fontSize: 12 }}
                            value={b.status}
                            onChange={(e) => updateStatus(b._id, e.target.value)}
                          >
                            <option value="pending">Pending</option>
                            <option value="assigned">Assigned</option>
                            <option value="active">Active</option>
                            <option value="completed">Completed</option>
                            <option value="cancelled">Cancelled</option>
                          </select>

                        </div>
                      </td>

                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </>
        )}

        {/* CAREGIVERS */}
        {activeTab === 'caregivers' && (
          <>
            <h2 className="section-title">Caregivers</h2>

            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Name</th>
                    <th>Specializations</th>
                    <th>Status</th>
                  </tr>
                </thead>

                <tbody>
                  {caregivers.map(c => (
                    <tr key={c._id}>
                      <td>{c.user?.name}</td>

                      <td>
                        {c.specializations?.join(', ')}
                      </td>

                      <td>
                        <span className={`badge ${c.isAvailable ? 'badge-teal' : 'badge-gray'}`}>
                          {c.isAvailable ? 'Available' : 'Busy'}
                        </span>
                      </td>

                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </>
        )}

      </main>
    </div>
  );
}
